#[derive(Debug, Default)]
struct OutboxProjectionReceipt {
    graph_events: usize,
    lineage_events: usize,
    lineage_event_hashes: Vec<String>,
    open_lineage_hashes: Vec<String>,
}

impl OutboxProjectionReceipt {
    fn record_lineage(&mut self, receipt: LineageReceipt) {
        self.lineage_events += 1;
        self.lineage_event_hashes.push(receipt.event_hash);
        self.open_lineage_hashes.push(receipt.open_lineage_hash);
    }
}

pub async fn drain_outbox_once(
    state: &LakeCatState,
    limit: usize,
) -> Result<LineageDrainResponse, LakeCatError> {
    let mut events = state
        .store
        .pending_outbox_events(Some("lakecat.lineage-and-graph"), limit)
        .await?;
    events.sort_by(|left, right| {
        left.created_at
            .cmp(&right.created_at)
            .then_with(|| left.event_id.cmp(&right.event_id))
    });
    let mut seen_event_ids = BTreeSet::new();
    for event in &events {
        if !seen_event_ids.insert(event.event_id.as_str()) {
            return Err(LakeCatError::Conflict(format!(
                "outbox pending batch contained duplicate event id hash {}",
                content_hash_bytes(event.event_id.as_bytes())
            )));
        }
    }
    let mut delivered = Vec::with_capacity(events.len());
    let mut event_types = Vec::with_capacity(events.len());
    let mut summaries = Vec::with_capacity(events.len());
    let mut graph_events = 0usize;
    let mut lineage_events = 0usize;
    for event in events {
        validate_outbox_event_evidence(&event)?;
        let receipt = project_outbox_event(state, &event).await?;
        graph_events += receipt.graph_events;
        lineage_events += receipt.lineage_events;
        summaries.push(lineage_drain_event_summary(&event, &receipt));
        event_types.push(event.event_type.clone());
        delivered.push(event.event_id.clone());
    }
    // Acknowledgement is all-or-retry: if any projection fails above, no pending
    // event is marked delivered and the outbox remains the recovery source.
    let projected = delivered.len();
    let delivered = state.store.mark_outbox_delivered(&delivered).await?;
    if delivered != projected {
        return Err(LakeCatError::Conflict(format!(
            "outbox drain acknowledgement mismatch: projected {projected} event(s) but marked {delivered} delivered"
        )));
    }
    Ok(LineageDrainResponse {
        delivered,
        event_types,
        graph_events,
        lineage_events,
        principal_subject: None,
        principal_kind: None,
        authorization_receipt_hash: None,
        authorization_receipt_action: None,
        request_identity_state: None,
        request_identity_source: None,
        typedid_envelope_hash: None,
        typedid_proof_hash: None,
        events: summaries,
    })
}

fn validate_outbox_event_evidence(event: &OutboxEvent) -> Result<(), LakeCatError> {
    let payload = event.payload.get("payload").unwrap_or(&event.payload);
    if !is_known_outbox_event_type(event.event_type.as_str()) {
        return Err(outbox_evidence_error(
            event,
            "outbox event type is not supported for projection",
        ));
    }
    validate_read_restriction_policy_hashes(
        event,
        payload.get("read-restriction"),
        "read restriction",
    )?;
    validate_read_restriction_policy_hashes(
        event,
        authorization_receipt_read_restriction(payload),
        "authorization receipt read restriction",
    )?;
    if event.event_type == "table.commit" {
        validate_table_commit_hash_evidence(event)?;
    }
    if event.event_type == "table.commits-listed" {
        validate_table_commit_history_event_evidence(event, payload)?;
    }
    if event.event_type == "table.scan-planned" {
        validate_scan_planned_event_evidence(event, payload)?;
    }
    if event.event_type == "table.scan-tasks-fetched" {
        validate_scan_tasks_fetched_event_evidence(event, payload)?;
    }
    if matches!(
        event.event_type.as_str(),
        "table.created" | "table.loaded" | "table.deleted" | "table.restored"
    ) {
        validate_table_lifecycle_event_evidence(event, payload)?;
    }
    if event.event_type == "credentials.vend-attempted" {
        validate_credential_vend_event_evidence(event, payload)?;
    }
    if event.event_type == "storage-profile.upserted" {
        validate_storage_profile_upsert_event_evidence(event, payload)?;
    }
    if event.event_type == "policy-binding.upserted" {
        validate_policy_binding_upsert_event_evidence(event, payload)?;
    }
    if event.event_type == "project.upserted" {
        validate_project_upsert_event_evidence(event, payload)?;
    }
    if event.event_type == "server.upserted" {
        validate_server_upsert_event_evidence(event, payload)?;
    }
    if event.event_type == "warehouse.upserted" {
        validate_warehouse_upsert_event_evidence(event, payload)?;
    }
    if event.event_type == "catalog.config-read" {
        validate_catalog_config_read_event_evidence(event, payload)?;
    }
    if event.event_type == "namespace.listed" {
        validate_namespace_list_event_evidence(event, payload)?;
    }
    if event.event_type == "view.listed" {
        validate_view_list_event_evidence(event, payload)?;
    }
    if matches!(
        event.event_type.as_str(),
        "view.upserted" | "view.loaded" | "view.dropped"
    ) {
        validate_view_lifecycle_event_evidence(event, payload)?;
    }
    if matches!(
        event.event_type.as_str(),
        "policy-binding.listed"
            | "project.listed"
            | "server.listed"
            | "storage-profile.listed"
            | "warehouse.listed"
    ) {
        validate_management_list_event_evidence(event, payload)?;
    }
    if matches!(
        event.event_type.as_str(),
        "namespace.created" | "namespace.dropped" | "namespace.loaded"
    ) {
        validate_namespace_lifecycle_event_evidence(event, payload)?;
    }
    if event.event_type == "view.version-receipts-listed" {
        validate_view_receipt_list_event_evidence(event, payload)?;
    }
    if event.event_type == "view.version-receipt-chains-listed" {
        validate_view_receipt_chain_event_evidence(event, payload)?;
    }
    if event.event_type == "querygraph.bootstrap" {
        validate_querygraph_bootstrap_event_evidence(event, payload)?;
    }
    Ok(())
}

fn is_known_outbox_event_type(event_type: &str) -> bool {
    matches!(
        event_type,
        "catalog.config-read"
            | "credentials.vend-attempted"
            | "namespace.created"
            | "namespace.dropped"
            | "namespace.listed"
            | "namespace.loaded"
            | "policy-binding.listed"
            | "policy-binding.upserted"
            | "project.listed"
            | "project.upserted"
            | "querygraph.bootstrap"
            | "server.listed"
            | "server.upserted"
            | "storage-profile.listed"
            | "storage-profile.upserted"
            | "table.commit"
            | "table.commits-listed"
            | "table.created"
            | "table.deleted"
            | "table.loaded"
            | "table.restored"
            | "table.scan-planned"
            | "table.scan-tasks-fetched"
            | "view.dropped"
            | "view.listed"
            | "view.loaded"
            | "view.upserted"
            | "view.version-receipt-chains-listed"
            | "view.version-receipts-listed"
            | "warehouse.listed"
            | "warehouse.upserted"
    )
}

fn validate_read_restriction_policy_hashes(
    event: &OutboxEvent,
    restriction: Option<&Value>,
    evidence_label: &str,
) -> Result<(), LakeCatError> {
    let Some(policy_hashes) = restriction.and_then(|restriction| restriction.get("policy-hashes"))
    else {
        return Ok(());
    };
    let Some(policy_hashes) = policy_hashes.as_array() else {
        return Err(outbox_evidence_error(
            event,
            &format!("{evidence_label} policy-hashes must be an array"),
        ));
    };
    if policy_hashes.is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{evidence_label} policy-hashes must not be empty"),
        ));
    }
    for policy_hash in policy_hashes {
        if !policy_hash
            .as_str()
            .is_some_and(is_full_sha256_digest_evidence)
        {
            return Err(outbox_evidence_error(
                event,
                &format!(
                    "{evidence_label} policy-hashes must contain full SHA-256 digest evidence"
                ),
            ));
        }
    }
    let mut seen = BTreeSet::new();
    if policy_hashes
        .iter()
        .filter_map(Value::as_str)
        .any(|policy_hash| !seen.insert(policy_hash))
    {
        return Err(outbox_evidence_error(
            event,
            &format!("{evidence_label} policy-hashes must be duplicate-free"),
        ));
    }
    Ok(())
}

fn validate_required_read_restriction_policy_hashes(
    event: &OutboxEvent,
    restriction: Option<&Value>,
    evidence_label: &str,
) -> Result<(), LakeCatError> {
    let Some(restriction) = restriction else {
        return Ok(());
    };
    if restriction.get("policy-hashes").is_none() {
        return Err(outbox_evidence_error(
            event,
            &format!("{evidence_label} must contain policy-hashes"),
        ));
    }
    validate_read_restriction_policy_hashes(event, Some(restriction), evidence_label)
}

fn authorization_receipt_read_restriction(payload: &Value) -> Option<&Value> {
    payload
        .get("authorization-receipt")?
        .get("context")?
        .get("read-restriction")
}

fn authorization_receipt_raw_credential_exception(payload: &Value) -> Option<&Value> {
    payload
        .get("authorization-receipt")?
        .get("context")?
        .get("lakecat:raw-credential-exception")
}

fn validate_table_commit_hash_evidence(event: &OutboxEvent) -> Result<(), LakeCatError> {
    let payload = event.payload.get("payload").unwrap_or(&event.payload);
    let Some(commit) = payload
        .get("commit")
        .or_else(|| event.payload.get("commit"))
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain commit",
        ));
    };
    let Some(root_table) = event.payload.get("table") else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain table identity",
        ));
    };
    let root_table = decode_table_lifecycle_identity(event, root_table, "table commit")?;
    if let Some(commit_table) = commit.get("table") {
        validate_table_lifecycle_table_hint(
            event,
            commit_table,
            &root_table,
            "table commit table",
        )?;
    }
    let Some(commit_principal) = commit.get("principal") else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain commit principal",
        ));
    };
    let commit_principal =
        decode_outbox_principal_value(event, commit_principal, "table commit principal")?;
    let Some(receipt_principal) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("principal"))
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain authorization receipt principal",
        ));
    };
    let receipt_principal = decode_outbox_principal_value(
        event,
        receipt_principal,
        "table commit authorization receipt principal",
    )?;
    validate_authorization_receipt_action(event, payload, "table commit")?;
    validate_authorization_receipt_allowed(event, payload, "table commit")?;
    validate_authorization_receipt_engine(event, payload, "table commit")?;
    validate_authorization_receipt_checked_at(event, payload, "table commit")?;
    if commit_principal != receipt_principal {
        return Err(outbox_evidence_error(
            event,
            "table commit principal does not match authorization receipt principal",
        ));
    }
    let Some(sequence_number) = commit
        .get("sequence_number")
        .or_else(|| commit.get("sequence-number"))
        .and_then(Value::as_u64)
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain unsigned sequence number",
        ));
    };
    if sequence_number == 0 {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence sequence number must be positive",
        ));
    }
    let Some(format_version) = commit
        .get("format_version")
        .or_else(|| commit.get("format-version"))
        .and_then(Value::as_u64)
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain unsigned format version",
        ));
    };
    if format_version == 0 {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence format version must be positive",
        ));
    }
    let Some(snapshot_id) = commit
        .get("snapshot_id")
        .or_else(|| commit.get("snapshot-id"))
        .and_then(Value::as_i64)
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain signed snapshot id",
        ));
    };
    if snapshot_id < 0 {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence snapshot id must be non-negative",
        ));
    }
    validate_required_rfc3339_string(
        event,
        commit,
        &["committed_at", "committed-at"],
        "table commit evidence committed_at timestamp",
    )?;
    if !commit
        .get("new_metadata_location")
        .or_else(|| commit.get("new-metadata-location"))
        .and_then(Value::as_str)
        .is_some_and(|location| !location.trim().is_empty())
    {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence must contain non-empty new metadata location",
        ));
    }
    if commit
        .get("previous_metadata_location")
        .or_else(|| commit.get("previous-metadata-location"))
        .is_some_and(|location| {
            !location
                .as_str()
                .is_some_and(|location| !location.trim().is_empty())
        })
    {
        return Err(outbox_evidence_error(
            event,
            "table commit evidence previous metadata location must be non-empty when present",
        ));
    }
    for field in ["request_hash", "response_hash", "idempotency_key_sha256"] {
        validate_required_full_hash_field(event, commit, field)?;
    }
    validate_optional_full_hash_field(event, commit, "policy_hash")?;
    Ok(())
}

fn decode_outbox_principal_value(
    event: &OutboxEvent,
    principal: &Value,
    label: &str,
) -> Result<Principal, LakeCatError> {
    serde_json::from_value(principal.clone()).map_err(|err| {
        outbox_evidence_error(event, &format!("{label} must be a valid principal: {err}"))
    })
}

fn validate_authorization_receipt_principal(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(receipt_principal) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("principal"))
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} evidence must contain authorization receipt principal"),
        ));
    };
    decode_outbox_principal_value(
        event,
        receipt_principal,
        &format!("{label} authorization receipt principal"),
    )?;
    validate_authorization_receipt_action(event, payload, label)?;
    validate_authorization_receipt_allowed(event, payload, label)?;
    validate_authorization_receipt_engine(event, payload, label)?;
    validate_authorization_receipt_checked_at(event, payload, label)?;
    Ok(())
}

fn validate_authorization_receipt_action(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(action) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("action"))
        .and_then(Value::as_str)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} evidence must contain authorization receipt action"),
        ));
    };
    if action.trim().is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} authorization receipt action must be non-empty"),
        ));
    }
    let action = serde_json::from_value::<CatalogAction>(Value::String(action.to_string()))
        .map_err(|err| {
            outbox_evidence_error(
                event,
                &format!(
                    "{label} authorization receipt action must be a known catalog action: {err}"
                ),
            )
        })?;
    if !authorization_receipt_action_matches_event(event.event_type.as_str(), &action) {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} authorization receipt action does not match outbox event type"),
        ));
    }
    Ok(())
}

fn authorization_receipt_action_matches_event(event_type: &str, action: &CatalogAction) -> bool {
    match event_type {
        "catalog.config-read" => matches!(action, CatalogAction::CatalogConfig),
        "credentials.vend-attempted" => matches!(action, CatalogAction::CredentialsVend),
        "namespace.created" => matches!(action, CatalogAction::NamespaceCreate),
        "namespace.dropped" => matches!(action, CatalogAction::NamespaceDrop),
        "namespace.listed" => matches!(action, CatalogAction::NamespaceList),
        "namespace.loaded" => matches!(action, CatalogAction::NamespaceLoad),
        "policy-binding.listed" | "policy-binding.upserted" => {
            matches!(action, CatalogAction::PolicyManage)
        }
        "project.listed" | "project.upserted" => matches!(action, CatalogAction::ProjectManage),
        "querygraph.bootstrap" => matches!(action, CatalogAction::GraphRead),
        "server.listed" | "server.upserted" => matches!(action, CatalogAction::ServerManage),
        "storage-profile.listed" | "storage-profile.upserted" => {
            matches!(action, CatalogAction::StorageProfileManage)
        }
        "table.commit" => matches!(action, CatalogAction::TableCommit),
        "table.commits-listed" | "table.loaded" => matches!(action, CatalogAction::TableLoad),
        "table.created" => matches!(action, CatalogAction::TableCreate),
        "table.deleted" => matches!(action, CatalogAction::TableDrop),
        "table.restored" => matches!(action, CatalogAction::TableRestore),
        "table.scan-planned" | "table.scan-tasks-fetched" => {
            matches!(action, CatalogAction::TablePlanScan)
        }
        "view.dropped" => matches!(action, CatalogAction::ViewDrop),
        "view.listed" => matches!(action, CatalogAction::ViewLoad),
        "view.loaded" | "view.version-receipts-listed" | "view.version-receipt-chains-listed" => {
            matches!(action, CatalogAction::ViewLoad)
        }
        "view.upserted" => matches!(action, CatalogAction::ViewManage),
        "warehouse.listed" | "warehouse.upserted" => {
            matches!(action, CatalogAction::WarehouseManage)
        }
        _ => false,
    }
}

fn validate_authorization_receipt_allowed(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(allowed) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("allowed"))
        .and_then(Value::as_bool)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} evidence must contain authorization receipt allowed decision"),
        ));
    };
    if !allowed {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} authorization receipt must allow replay projection"),
        ));
    }
    Ok(())
}

fn validate_authorization_receipt_engine(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(engine) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("engine"))
        .and_then(Value::as_str)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} evidence must contain authorization receipt engine"),
        ));
    };
    if engine.trim().is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} authorization receipt engine must be non-empty"),
        ));
    }
    Ok(())
}

fn validate_authorization_receipt_checked_at(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(checked_at) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("checked_at"))
        .and_then(Value::as_str)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} evidence must contain authorization receipt checked_at timestamp"),
        ));
    };
    if checked_at.trim().is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} authorization receipt checked_at timestamp must be non-empty"),
        ));
    }
    chrono::DateTime::parse_from_rfc3339(checked_at).map_err(|err| {
        outbox_evidence_error(
            event,
            &format!("{label} authorization receipt checked_at timestamp must be RFC3339: {err}"),
        )
    })?;
    Ok(())
}

fn validate_required_rfc3339_string(
    event: &OutboxEvent,
    value: &Value,
    field_names: &[&str],
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(timestamp) = field_names
        .iter()
        .find_map(|field_name| value.get(*field_name))
        .and_then(Value::as_str)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} must be present"),
        ));
    };
    if timestamp.trim().is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} must be non-empty"),
        ));
    }
    chrono::DateTime::parse_from_rfc3339(timestamp)
        .map_err(|err| outbox_evidence_error(event, &format!("{label} must be RFC3339: {err}")))?;
    Ok(())
}

fn validate_table_commit_history_event_evidence(
    event: &OutboxEvent,
    payload: &Value,
) -> Result<(), LakeCatError> {
    let table = validate_required_outbox_table_identity(event, "table commit-history")?;
    validate_table_lifecycle_payload_scope(event, payload, &table, "table commit-history")?;
    validate_required_payload_table_hint(event, payload, &table, "table commit-history")?;
    let Some(receipt_principal) = payload
        .get("authorization-receipt")
        .and_then(|receipt| receipt.get("principal"))
    else {
        return Err(outbox_evidence_error(
            event,
            "table commit-history evidence must contain authorization receipt principal",
        ));
    };
    let receipt_principal = decode_outbox_principal_value(
        event,
        receipt_principal,
        "table commit-history authorization receipt principal",
    )?;
    validate_authorization_receipt_action(event, payload, "table commit-history")?;
    validate_authorization_receipt_allowed(event, payload, "table commit-history")?;
    validate_authorization_receipt_engine(event, payload, "table commit-history")?;
    validate_authorization_receipt_checked_at(event, payload, "table commit-history")?;
    let commit_hashes = validate_required_full_hash_array_field(event, payload, "commit-hashes")?;
    validate_unique_hash_array(event, &commit_hashes, "table commit-history commit-hashes")?;
    let sequence_numbers = payload
        .get("sequence-numbers")
        .and_then(Value::as_array)
        .ok_or_else(|| {
            outbox_evidence_error(
                event,
                "table commit-history evidence must contain sequence-numbers",
            )
        })?;
    let mut previous_sequence_number = None;
    for sequence_number in sequence_numbers {
        let Some(sequence_number) = sequence_number.as_u64() else {
            return Err(outbox_evidence_error(
                event,
                "table commit-history sequence-numbers must be unsigned integers",
            ));
        };
        if sequence_number == 0 {
            return Err(outbox_evidence_error(
                event,
                "table commit-history sequence-numbers must be positive",
            ));
        }
        if previous_sequence_number
            .map(|previous| sequence_number <= previous)
            .unwrap_or(false)
        {
            return Err(outbox_evidence_error(
                event,
                "table commit-history sequence-numbers must be strictly increasing",
            ));
        }
        previous_sequence_number = Some(sequence_number);
    }
    let Some(expected_commit_count) = payload.get("commit-count").and_then(Value::as_u64) else {
        return Err(outbox_evidence_error(
            event,
            "table commit-history evidence must contain commit-count",
        ));
    };
    if commit_hashes.len() as u64 != expected_commit_count {
        return Err(outbox_evidence_error(
            event,
            "table commit-history commit-count does not match commit-hashes",
        ));
    }
    if sequence_numbers.len() as u64 != expected_commit_count {
        return Err(outbox_evidence_error(
            event,
            "table commit-history commit-count does not match sequence-numbers",
        ));
    }
    validate_string_field_equals(
        event,
        payload,
        "principal-subject",
        &receipt_principal.subject,
        "table commit-history",
    )?;
    validate_string_field_equals(
        event,
        payload,
        "principal-kind",
        principal_kind_name(&receipt_principal.kind),
        "table commit-history",
    )?;
    Ok(())
}

fn validate_table_lifecycle_event_evidence(
    event: &OutboxEvent,
    payload: &Value,
) -> Result<(), LakeCatError> {
    let Some(table_value) = event.payload.get("table") else {
        return Err(outbox_evidence_error(
            event,
            "table lifecycle evidence must contain table identity",
        ));
    };
    let table = decode_table_lifecycle_identity(event, table_value, "table lifecycle")?;
    validate_authorization_receipt_principal(event, payload, "table lifecycle")?;
    validate_table_lifecycle_payload_scope(event, payload, &table, "table lifecycle")?;
    if matches!(
        event.event_type.as_str(),
        "table.created" | "table.loaded" | "table.restored"
    ) {
        require_positive_i64_field(event, payload, "format-version", "table lifecycle")?;
        if payload.get("version").and_then(Value::as_u64).is_none() {
            return Err(outbox_evidence_error(
                event,
                "table lifecycle evidence must contain unsigned version",
            ));
        }
    }

    if let Some(payload_table) = payload.get("table") {
        validate_table_lifecycle_table_hint(
            event,
            payload_table,
            &table,
            "table lifecycle payload table",
        )?;
    }
    let soft_delete = payload
        .get("soft-delete")
        .or_else(|| event.payload.get("soft-delete"));
    if event.event_type == "table.deleted" && soft_delete.is_none() {
        return Err(outbox_evidence_error(
            event,
            "table lifecycle delete evidence must contain soft-delete",
        ));
    }
    if let Some(soft_delete) = soft_delete {
        let Some(soft_delete) = soft_delete.as_object() else {
            return Err(outbox_evidence_error(
                event,
                "table lifecycle soft-delete evidence must be an object",
            ));
        };
        let Some(soft_delete_table) = soft_delete.get("table") else {
            return Err(outbox_evidence_error(
                event,
                "table lifecycle soft-delete evidence must contain table identity",
            ));
        };
        validate_table_lifecycle_table_hint(
            event,
            soft_delete_table,
            &table,
            "table lifecycle soft-delete table",
        )?;
        if soft_delete.get("version").and_then(Value::as_u64).is_none() {
            return Err(outbox_evidence_error(
                event,
                "table lifecycle soft-delete evidence must contain unsigned version",
            ));
        }
        if event.event_type == "table.deleted"
            && soft_delete.get("version").and_then(Value::as_u64) == Some(0)
        {
            return Err(outbox_evidence_error(
                event,
                "table lifecycle soft-delete version must be positive",
            ));
        }
        require_positive_i64_field(
            event,
            &Value::Object(soft_delete.clone()),
            "format-version",
            "table lifecycle soft-delete",
        )?;
        optional_non_empty_string_field(
            event,
            &Value::Object(soft_delete.clone()),
            "metadata-location",
            "table lifecycle soft-delete",
        )?;
    }

    optional_non_empty_string_field(event, payload, "metadata-location", "table lifecycle")?;
    optional_non_empty_string_field(event, payload, "location", "table lifecycle")?;
    Ok(())
}

fn decode_table_lifecycle_identity(
    event: &OutboxEvent,
    table: &Value,
    label: &str,
) -> Result<TableIdent, LakeCatError> {
    serde_json::from_value(table.clone()).map_err(|_| {
        outbox_evidence_error(
            event,
            &format!("{label} evidence has invalid table identity"),
        )
    })
}

fn validate_table_lifecycle_payload_scope(
    event: &OutboxEvent,
    payload: &Value,
    table: &TableIdent,
    label: &str,
) -> Result<(), LakeCatError> {
    if let Some(warehouse) = payload.get("warehouse") {
        let warehouse = warehouse
            .as_str()
            .filter(|warehouse| !warehouse.is_empty())
            .ok_or_else(|| {
                outbox_evidence_error(
                    event,
                    &format!("{label} warehouse must be a non-empty string when present"),
                )
            })?;
        if warehouse != table.warehouse.as_str() {
            return Err(outbox_evidence_error(
                event,
                &format!("{label} warehouse does not match table identity"),
            ));
        }
    }
    if let Some(namespace) = payload.get("namespace") {
        let namespace = table_lifecycle_namespace_from_value(event, namespace, label)?;
        if namespace != table.namespace {
            return Err(outbox_evidence_error(
                event,
                &format!("{label} namespace does not match table identity"),
            ));
        }
    }
    if let Some(table_name) = payload.get("table") {
        if table_name.is_object() {
            return Ok(());
        }
        let table_name = table_name
            .as_str()
            .filter(|table_name| !table_name.is_empty())
            .ok_or_else(|| {
                outbox_evidence_error(
                    event,
                    &format!("{label} table must be a non-empty string when present"),
                )
            })?;
        if table_name != table.name.as_str() {
            return Err(outbox_evidence_error(
                event,
                &format!("{label} table name does not match table identity"),
            ));
        }
    }
    Ok(())
}

fn validate_table_lifecycle_table_hint(
    event: &OutboxEvent,
    table_hint: &Value,
    table: &TableIdent,
    label: &str,
) -> Result<(), LakeCatError> {
    if table_hint.is_object() {
        let hinted_table = decode_table_lifecycle_identity(event, table_hint, label)?;
        if hinted_table != *table {
            return Err(outbox_evidence_error(
                event,
                &format!("{label} does not match table identity"),
            ));
        }
        return Ok(());
    }
    let table_name = table_hint
        .as_str()
        .filter(|table_name| !table_name.is_empty())
        .ok_or_else(|| {
            outbox_evidence_error(
                event,
                &format!("{label} must be a table identity object or non-empty table name"),
            )
        })?;
    if table_name != table.name.as_str() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} name does not match table identity"),
        ));
    }
    Ok(())
}

fn validate_scan_planned_event_evidence(
    event: &OutboxEvent,
    payload: &Value,
) -> Result<(), LakeCatError> {
    let table = validate_required_outbox_table_identity(event, "scan-planned")?;
    validate_required_payload_table_hint(event, payload, &table, "scan-planned")?;
    validate_required_unsigned_count_field(event, payload, "scan-task-count", "scan-planned")?;
    validate_authorization_receipt_principal(event, payload, "scan-planned")?;

    let requested_projection = validate_required_non_empty_string_array_field(
        event,
        payload,
        "requested-projection",
        "scan-planned",
    )?;
    let effective_projection = validate_required_non_empty_string_array_field(
        event,
        payload,
        "effective-projection",
        "scan-planned",
    )?;
    validate_effective_evidence_subset(
        event,
        "scan-planned effective-projection",
        &effective_projection,
        "requested-projection",
        &requested_projection,
        false,
    )?;
    validate_effective_projection_matches_read_restriction(
        event,
        payload,
        "scan-planned",
        &effective_projection,
    )?;
    validate_required_read_restriction_policy_hashes(
        event,
        payload.get("read-restriction"),
        "scan-planned read-restriction",
    )?;
    validate_required_read_restriction_policy_hashes(
        event,
        authorization_receipt_read_restriction(payload),
        "scan-planned authorization receipt read-restriction",
    )?;
    validate_read_restriction_receipt_match(event, payload, "scan-planned")?;
    validate_scan_read_restriction_row_predicate(event, payload, "scan-planned")?;

    let requested_stats = validate_required_non_empty_string_array_field(
        event,
        payload,
        "requested-stats-fields",
        "scan-planned",
    )?;
    let effective_stats = validate_required_non_empty_string_array_field(
        event,
        payload,
        "effective-stats-fields",
        "scan-planned",
    )?;
    validate_effective_evidence_subset(
        event,
        "scan-planned effective-stats-fields",
        &effective_stats,
        "requested-stats-fields",
        &requested_stats,
        false,
    )?;
    validate_effective_stats_matches_read_restriction(
        event,
        payload,
        "scan-planned",
        &effective_stats,
    )?;
    validate_scan_read_restriction_purpose_and_ttl(event, payload, "scan-planned")?;
    Ok(())
}

fn validate_scan_tasks_fetched_event_evidence(
    event: &OutboxEvent,
    payload: &Value,
) -> Result<(), LakeCatError> {
    let table = validate_required_outbox_table_identity(event, "scan-tasks-fetched")?;
    validate_required_payload_table_hint(event, payload, &table, "scan-tasks-fetched")?;
    validate_authorization_receipt_principal(event, payload, "scan-tasks-fetched")?;
    for field in [
        "file-scan-task-count",
        "delete-file-count",
        "child-plan-task-count",
    ] {
        validate_required_unsigned_count_field(event, payload, field, "scan-tasks-fetched")?;
    }

    let required_projection = validate_required_non_empty_string_array_field(
        event,
        payload,
        "required-projection",
        "scan-tasks-fetched",
    )?;
    let effective_projection = validate_required_non_empty_string_array_field(
        event,
        payload,
        "effective-projection",
        "scan-tasks-fetched",
    )?;
    validate_effective_evidence_subset(
        event,
        "scan-tasks-fetched effective-projection",
        &effective_projection,
        "required-projection",
        &required_projection,
        true,
    )?;
    validate_effective_projection_matches_read_restriction(
        event,
        payload,
        "scan-tasks-fetched",
        &effective_projection,
    )?;
    validate_required_read_restriction_policy_hashes(
        event,
        payload.get("read-restriction"),
        "scan-tasks-fetched read-restriction",
    )?;
    validate_required_read_restriction_policy_hashes(
        event,
        authorization_receipt_read_restriction(payload),
        "scan-tasks-fetched authorization receipt read-restriction",
    )?;
    validate_read_restriction_receipt_match(event, payload, "scan-tasks-fetched")?;
    validate_scan_read_restriction_row_predicate(event, payload, "scan-tasks-fetched")?;
    let Some(required_filters) = payload.get("required-filters") else {
        return Err(outbox_evidence_error(
            event,
            "scan-tasks-fetched evidence must contain required-filters",
        ));
    };
    if !required_filters.is_array() {
        return Err(outbox_evidence_error(
            event,
            "scan-tasks-fetched required-filters must be an array",
        ));
    }
    validate_scan_required_filters_match_row_predicate(event, payload, "scan-tasks-fetched")?;
    validate_scan_read_restriction_purpose_and_ttl(event, payload, "scan-tasks-fetched")?;
    Ok(())
}

fn validate_scan_required_filters_match_row_predicate(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(read_restriction) = payload.get("read-restriction") else {
        return Ok(());
    };
    let Some(row_predicate) = read_restriction.get("row-predicate") else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction must contain row-predicate"),
        ));
    };
    let Some(required_filters) = payload.get("required-filters").and_then(Value::as_array) else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} required-filters must be an array"),
        ));
    };
    let expected_filters = vec![row_predicate.clone()];
    if required_filters.as_slice() != expected_filters.as_slice() {
        return Err(outbox_evidence_error(
            event,
            &format!(
                "{label} required-filters must exactly preserve read-restriction row-predicate"
            ),
        ));
    }
    Ok(())
}

fn validate_scan_read_restriction_purpose_and_ttl(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(read_restriction) = payload.get("read-restriction") else {
        return Ok(());
    };
    if read_restriction
        .get("purpose")
        .and_then(Value::as_str)
        .is_none_or(|purpose| purpose.trim().is_empty())
    {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction purpose must not be blank"),
        ));
    }
    let Some(ttl_seconds) = read_restriction
        .get("max-credential-ttl-seconds")
        .and_then(Value::as_u64)
    else {
        return Err(outbox_evidence_error(
            event,
            &format!(
                "{label} read-restriction max-credential-ttl-seconds must be a positive integer"
            ),
        ));
    };
    if ttl_seconds == 0 {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction max-credential-ttl-seconds must be positive"),
        ));
    }
    Ok(())
}

fn validate_scan_read_restriction_row_predicate(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    let Some(read_restriction) = payload.get("read-restriction") else {
        return Ok(());
    };
    let Some(row_predicate) = read_restriction.get("row-predicate") else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction must contain row-predicate"),
        ));
    };
    let Some(row_predicate) = row_predicate.as_object() else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction row-predicate must be an object"),
        ));
    };
    if row_predicate.is_empty() {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction row-predicate must contain predicate evidence"),
        ));
    }
    let Some(predicate_type) = row_predicate
        .get("type")
        .and_then(Value::as_str)
        .filter(|predicate_type| !predicate_type.trim().is_empty())
    else {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction row-predicate.type must not be blank"),
        ));
    };
    if predicate_type == "always-true" {
        return Ok(());
    }
    if row_predicate
        .get("term")
        .and_then(Value::as_str)
        .is_none_or(|term| term.trim().is_empty())
    {
        return Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction row-predicate.term must not be blank"),
        ));
    }
    if matches!(predicate_type, "eq" | "not-eq") && !row_predicate.contains_key("value") {
        return Err(outbox_evidence_error(
            event,
            &format!(
                "{label} read-restriction row-predicate.value is required for {predicate_type} predicate evidence"
            ),
        ));
    }
    Ok(())
}

fn validate_read_restriction_receipt_match(
    event: &OutboxEvent,
    payload: &Value,
    label: &str,
) -> Result<(), LakeCatError> {
    match (
        payload.get("read-restriction"),
        authorization_receipt_read_restriction(payload),
    ) {
        (None, None) => Ok(()),
        (Some(read_restriction), Some(receipt_read_restriction))
            if read_restriction == receipt_read_restriction =>
        {
            Ok(())
        }
        (Some(_), None) => Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction must be captured in authorization receipt context"),
        )),
        (None, Some(_)) => Err(outbox_evidence_error(
            event,
            &format!(
                "{label} authorization receipt read-restriction must match top-level read-restriction"
            ),
        )),
        (Some(_), Some(_)) => Err(outbox_evidence_error(
            event,
            &format!("{label} read-restriction must match authorization receipt context"),
        )),
    }
}

