    #[tokio::test]
    async fn namespaces_load_and_drop_through_catalog_routes() {
        let store = MemoryCatalogStore::new();
        store
            .upsert_project(
                ProjectRecord::new(
                    "default",
                    None,
                    Some("Default Project".to_string()),
                    std::collections::BTreeMap::new(),
                    Principal::anonymous(),
                )
                .unwrap(),
            )
            .await
            .unwrap();
        store
            .upsert_warehouse(
                WarehouseRecord::new(
                    WarehouseName::new("local").unwrap(),
                    "default",
                    Some("file:///tmp/lakecat".to_string()),
                    std::collections::BTreeMap::new(),
                    Principal::anonymous(),
                )
                .unwrap(),
            )
            .await
            .unwrap();
        let app = app(LakeCatState::new(
            WarehouseName::new("local").unwrap(),
            store,
        ));

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/catalog/v1/namespaces/empty")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NOT_FOUND);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/catalog/v1/namespaces")
                    .header("content-type", "application/json")
                    .body(Body::from(r#"{"namespace":["empty"]}"#))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/catalog/v1/namespaces/empty")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let body = axum::body::to_bytes(response.into_body(), usize::MAX)
            .await
            .unwrap();
        let payload: serde_json::Value = serde_json::from_slice(&body).unwrap();
        assert_eq!(payload["namespace"], serde_json::json!(["empty"]));

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri("/catalog/v1/namespaces/empty")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NO_CONTENT);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/catalog/v1/namespaces/empty")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NOT_FOUND);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/catalog/v1/local/namespaces")
                    .header("content-type", "application/json")
                    .body(Body::from(r#"{"namespace":["prefixed"]}"#))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/catalog/v1/local/namespaces/prefixed")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri("/catalog/v1/local/namespaces/prefixed")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::NO_CONTENT);

        let response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/catalog/v1/namespaces/default/tables")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        r#"{"name":"events","location":"file:///tmp/events","metadata":{"format-version":3}}"#,
                    ))
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri("/catalog/v1/namespaces/default")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::CONFLICT);
    }

    #[tokio::test]
    async fn authorization_headers_resolve_typed_principal() {
        let governance = Arc::new(RecordingGovernance::default());
        let app = app(LakeCatState::new(
            WarehouseName::new("local").unwrap(),
            MemoryCatalogStore::new(),
        )
        .with_integrations(
            default_sail_engine(),
            governance.clone(),
            NoopCatalogGraphSink::new(),
            HashOnlyLineageSink::new(),
        ));
        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/catalog/v1/config")
                    .header("x-lakecat-principal", "alice@example.com")
                    .header("x-lakecat-principal-kind", "human")
                    .body(Body::empty())
                    .unwrap(),
            )
            .await
            .unwrap();
        assert_eq!(response.status(), StatusCode::OK);
        let principals = governance.principals.lock().await;
        assert_eq!(principals[0].subject, "alice@example.com");
        assert_eq!(principals[0].kind, PrincipalKind::Human);
        drop(principals);
        let contexts = governance.contexts.lock().await;
        assert_eq!(
            contexts[0]["request-identity"]["source"],
            serde_json::json!("x-lakecat-principal")
        );
        assert_eq!(
            contexts[0]["request-identity"]["principal"]["subject"],
            serde_json::json!("alice@example.com")
        );
    }

